function minVisibleWhiteTiles(floor, numCarpets, carpetLen) {
    const n = floor.length;
    let visibleWhiteCount = 0;
    for (let i = 0; i < n; i++) {
        if (floor[i] === '1') visibleWhiteCount++;
    }

    let coveredTiles = 0;
    for (let i = 0; i < n; i++) {
        if (floor[i] === '1') {
            let start = Math.max(0, i - carpetLen + 1);
            let end = Math.min(n - carpetLen, i);
            let maxCover = 0;
            for (let firstTile = start; firstTile <= end; firstTile++) {
                let cover = 0;
                for (let j = firstTile; j < firstTile + carpetLen; j++) {
                    if (floor[j] === '1') cover ++;
                }
                maxCover = Math.max(maxCover, cover);
            }

            coveredTiles += maxCover;
            --numCarpets;
            if (numCarpets === 0) break;
        }
    }

    return visibleWhiteCount - coveredTiles;
}
```

    This function works as follows:

1. Loops through the floor once to count the number of white tiles (visible_white_count).
2. Begins a second loop through the floor to check possible locations for the carpets for maximum overlapping of white tiles.
3. Loops through subarrays with a length of carpetLen to find a position having the maximum number of white tiles (max_cover).
4. Adds max_cover to the covered_tiles.
5. Decreases the number of available carpets (numCarpets) by 1.
6. Checks whether every carpet is used.
7. Returns the difference between the visible_white_count and covered_tiles.

